2. import { render, screen, fireEvent } from '@testing-library/react';
3. import userEvent from '@testing-library/user-event';
4. import React from 'react';
5. import { SessionForm } from '../../../components/host/SessionForm';
6. 
7. describe('SessionForm', () => {
8.   it('renders all 5 question category sections', () => {
9.     render(<SessionForm onSubmit={vi.fn()} />);
10.     expect(screen.getByText('Color')).toBeInTheDocument();
11.     expect(screen.getByText('Region')).toBeInTheDocument();
12.     expect(screen.getByText('Grape Variety')).toBeInTheDocument();
13.     expect(screen.getByText('Vintage Year')).toBeInTheDocument();
14.     expect(screen.getByText('Wine Name')).toBeInTheDocument();
15.   });
16. 
17.   it('timer slider is present with default value 60', () => {
18.     render(<SessionForm onSubmit={vi.fn()} />);
19.     const slider = screen.getByRole('slider', { name: /timer/i });
20.     expect(slider).toBeInTheDocument();
21.     expect((slider as HTMLInputElement).value).toBe('60');
22.     expect((slider as HTMLInputElement).min).toBe('15');
23.     expect((slider as HTMLInputElement).max).toBe('120');
24.   });
25. 
26.   it('color distractors have default values pre-filled', () => {
27.     render(<SessionForm onSubmit={vi.fn()} />);
28.     // Correct answer and distractors are all distinct
29.     expect(screen.getByDisplayValue('Rouge')).toBeInTheDocument();  // correct answer
30.     expect(screen.getByDisplayValue('Blanc')).toBeInTheDocument();   // distractor 1
31.     expect(screen.getByDisplayValue('Rosé')).toBeInTheDocument();    // distractor 2
32.     expect(screen.getByDisplayValue('Orange')).toBeInTheDocument();  // distractor 3
33.   });
34. 
35.   it('vintage_year distractors have default values pre-filled', () => {
36.     render(<SessionForm onSubmit={vi.fn()} />);
37.     expect(screen.getByDisplayValue('2015')).toBeInTheDocument();
38.     expect(screen.getByDisplayValue('2016')).toBeInTheDocument();
39.     expect(screen.getByDisplayValue('2018')).toBeInTheDocument();
40.   });
41. 
42.   it('correct answer fields are pre-filled with example values by default', () => {
43.     render(<SessionForm onSubmit={vi.fn()} />);
44.     const correctAnswerInputs = screen.getAllByPlaceholderText(/correct answer/i);
45.     // All correct answer fields should have a non-empty default value
46.     correctAnswerInputs.forEach((input) => {
47.       expect((input as HTMLInputElement).value).not.toBe('');
48.     });
49.   });
50. 
51.   it('grape_variety has pre-filled distractors', () => {
52.     render(<SessionForm onSubmit={vi.fn()} />);
53.     expect(screen.getByDisplayValue('Pinot Noir')).toBeInTheDocument();
54.     expect(screen.getByDisplayValue('Syrah')).toBeInTheDocument();
55.     expect(screen.getByDisplayValue('Merlot')).toBeInTheDocument();
56.   });
57. 
58.   it('calls onSubmit with correct shape when form is filled and submitted', async () => {
59.     const onSubmit = vi.fn();
60.     render(<SessionForm onSubmit={onSubmit} hostId="TANNIC-FALCON" />);
61. 
62.     // Fill wine name
63.     await userEvent.type(screen.getByPlaceholderText(/château margaux 2015/i), 'Château Test');
64. 
65.     // All inputs already have defaults — just submit
66.     fireEvent.click(screen.getByRole('button', { name: /create tasting/i }));
67.     expect(onSubmit).toHaveBeenCalledOnce();
68.     const payload = onSubmit.mock.calls[0][0];
69.     expect(payload).toHaveProperty('wines');
70.     expect(payload).toHaveProperty('timerSeconds', 60);
71.     expect(payload).toHaveProperty('hostId', 'TANNIC-FALCON');
72.   });
73. 
74.   it('renders optional tasting title input', () => {
75.     render(<SessionForm onSubmit={vi.fn()} />);
76.     const titleInput = screen.getByRole('textbox', { name: /tasting title/i });
77.     expect(titleInput).toBeInTheDocument();
78.     expect((titleInput as HTMLInputElement).value).toBe('');
79.   });
80. 
81.   it('uses custom title in payload when provided', async () => {
82.     const onSubmit = vi.fn();
83.     render(<SessionForm onSubmit={onSubmit} hostId="TANNIC-FALCON" />);
84. 
85.     await userEvent.type(screen.getByPlaceholderText(/château margaux 2015/i), 'Château Test');
86.     await userEvent.type(screen.getByRole('textbox', { name: /tasting title/i }), 'My Custom Title');
87.     fireEvent.click(screen.getByRole('button', { name: /create tasting/i }));
88. 
89.     expect(onSubmit).toHaveBeenCalledOnce();
90.     expect(onSubmit.mock.calls[0][0]).toHaveProperty('title', 'My Custom Title');
91.   });
92. 
93.   it('falls back to first wine name as title when title input is empty', async () => {
94.     const onSubmit = vi.fn();
95.     render(<SessionForm onSubmit={onSubmit} hostId="TANNIC-FALCON" />);
96. 
97.     await userEvent.type(screen.getByPlaceholderText(/château margaux 2015/i), 'My Wine');
98.     fireEvent.click(screen.getByRole('button', { name: /create tasting/i }));
99. 
100.     expect(onSubmit).toHaveBeenCalledOnce();
101.     expect(onSubmit.mock.calls[0][0]).toHaveProperty('title', 'My Wine');
102.   });
103. 
104.   it('renders Edit Blind Tasting heading and Update Tasting button when isEditing=true', () => {
105.     render(<SessionForm onSubmit={vi.fn()} isEditing />);
106.     expect(screen.getByRole('heading', { name: /edit blind tasting/i })).toBeInTheDocument();
107.     expect(screen.getByRole('button', { name: /update tasting/i })).toBeInTheDocument();
108.   });
109. 
110.   it('pre-fills wine fields when initialWines provided', () => {
111.     const initialWines = [{
112.       name: 'Existing Wine',
113.       questions: [
114.         { category: 'color' as const, correctAnswer: 'Rouge', distractors: ['Blanc', 'Rosé', 'Orange'] as [string, string, string] },
115.         { category: 'region' as const, correctAnswer: 'France', distractors: ['Italy', 'Spain', 'USA'] as [string, string, string] },
116.         { category: 'grape_variety' as const, correctAnswer: 'Merlot', distractors: ['Syrah', 'Pinot Noir', 'Cabernet'] as [string, string, string] },
117.         { category: 'vintage_year' as const, correctAnswer: '2020', distractors: ['2018', '2019', '2021'] as [string, string, string] },
118.         { category: 'wine_name' as const, correctAnswer: 'Test Wine', distractors: ['A', 'B', 'C'] as [string, string, string] },
119.       ],
120.     }];
121.     render(<SessionForm onSubmit={vi.fn()} initialWines={initialWines} />);
122.     expect(screen.getByDisplayValue('Existing Wine')).toBeInTheDocument();
123.   });
124. 
125.   it('pre-fills title field when initialTitle provided', () => {
126.     render(<SessionForm onSubmit={vi.fn()} initialTitle="Friday Night Tasting" isEditing />);
127.     const titleInput = screen.getByRole('textbox', { name: /tasting title/i });
128.     expect((titleInput as HTMLInputElement).value).toBe('Friday Night Tasting');
129.   });
130. });
131. 
