1. import { useEffect, useCallback, useRef } from 'react';
2. import type PartySocket from 'partysocket';
3. import { createSocket } from '../lib/socket';
4. import { useHostStore } from '../stores/hostStore';
5. import { saveSession, mergeSession } from '../lib/sessionStorage';
6. import type {
7.   CreateSessionPayload,
8.   LobbyUpdatedPayload,
9.   QuestionPayload,
10.   HostRevealPayload,
11.   QuestionLeaderboardPayload,
12.   RoundLeaderboardPayload,
13.   FinalLeaderboardPayload,
14.   ParticipantAnsweredPayload,
15.   HostStateSnapshot,
16.   SessionsListPayload,
17. } from '../types/events';
18. 
19. /** Host socket hook — connects to a specific session room (4-digit code). */
20. export function useHostSocket(code: string) {
21.   const socketRef = useRef<PartySocket | null>(null);
22.   const pendingTitleRef = useRef<string>('');
23. 
24.   useEffect(() => {
25.     if (!code) return;
26.     const socket = createSocket(code);
27.     socketRef.current = socket;
28. 
29.     const { hostId } = useHostStore.getState();
30. 
31.     // Auto-rejoin if host already owns this session
32.     socket.addEventListener('open', () => {
33.       if (hostId) {
34.         socket.send(JSON.stringify({ type: 'rejoin_host', hostId }));
35.       }
36.     });
37. 
38.     const onMessage = (event: MessageEvent<string>) => {
39.       let msg: { type: string; [key: string]: unknown };
40.       try {
41.         msg = JSON.parse(event.data);
42.       } catch {
43.         return;
44.       }
45. 
46.       const store = useHostStore.getState();
47. 
48.       switch (msg.type) {
49.         case 'session:created': {
50.           const { code: sessionCode, hostId: returnedHostId } = msg as unknown as {
51.             code: string;
52.             hostId: string;
53.           };
54.           store.setCode(sessionCode);
55.           if (returnedHostId) store.setHostId(returnedHostId);
56.           store.setPhase('lobby');
57.           // Persist to localStorage so the dashboard can show this session
58.           // even when KV is not configured (local dev).
59.           saveSession(returnedHostId ?? store.hostId, {
60.             code: sessionCode,
61.             title: pendingTitleRef.current || sessionCode,
62.             createdAt: new Date().toISOString(),
63.             status: 'waiting',
64.             participantCount: 0,
65.           });
66.           break;
67.         }
68.         case 'host:state_snapshot': {
69.           const snap = msg as unknown as HostStateSnapshot;
70.           store.setCode(snap.code);
71.           if (snap.hostId) store.setHostId(snap.hostId);
72.           store.setParticipants(snap.participants);
73.           if (snap.question) {
74.             store.setCurrentQuestion(snap.question as QuestionPayload);
75.           }
76.           store.setRankings(snap.rankings);
77.           // Restore totalRounds from wines list in the snapshot
78.           if (snap.wines?.length) {
79.             store.setTotalRounds(snap.wines.length);
80.           }
81.           // Restore phase
82.           const phaseMap: Record<string, ReturnType<typeof store.setPhase> extends void ? Parameters<typeof store.setPhase>[0] : never> = {
83.             waiting: 'lobby',
84.             question_open: 'question',
85.             question_paused: 'question',
86.             question_revealed: 'revealed',
87.             question_leaderboard: 'questionLeaderboard',
88.             round_leaderboard: 'roundLeaderboard',
89.             ended: 'finalLeaderboard',
90.           };
91.           const frontPhase = phaseMap[snap.phase as string] as Parameters<typeof store.setPhase>[0];
92.           if (frontPhase) store.setPhase(frontPhase);
93.           break;
