 import { useState } from 'react';
 import {
   Combobox,
   ComboboxInput as HeadlessComboboxInput,
   ComboboxOption,
   ComboboxOptions,
 } from '@headlessui/react';

 export interface ComboboxInputProps {
   options: string[];
   value: string;
   onChange: (value: string) => void;
   placeholder?: string;
   label?: string;
   id?: string;
   className?: string;
   inputClassName?: string;
 }

 export function ComboboxInput({
   options,
   value,
   onChange,
   placeholder,
   label = 'Select an option',
   id,
   className,
   inputClassName,
 }: ComboboxInputProps) {
   const [query, setQuery] = useState('');

   const filtered =
     query === ''
       ? options
       : options.filter((o) => o.toLowerCase().includes(query.toLowerCase()));

   const showAdd =
     query !== '' &&
     !options.some((o) => o.toLowerCase() === query.toLowerCase());

   return (
     <Combobox
       value={value}
       onChange={(v: string) => {
         onChange(v);
         setQuery('');
       }}
     >
       <div className={className ?? ''}>
         <label className="sr-only" htmlFor={id}>
           {label}
         </label>

         <HeadlessComboboxInput
             id={id}
             aria-label={label}
             className={inputClassName ?? "w-full border border-slate-300 rounded-lg px-3 py-2 text-slate-800 placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-wine-400"}
             placeholder={placeholder}
             displayValue={(v: string) => v}
             onChange={(e) => setQuery(e.target.value)}
             onBlur={() => {
               if (query.trim() && query.trim() !== value) {
                 onChange(query.trim());
               }
               setQuery('');
             }}
           />

