1. import React, { useState, useEffect } from 'react';
2. import type { CreateSessionPayload, CreateWinePayload, QuestionCategory } from '../../types/events';
3. import { ComboboxInput } from '../common/ComboboxInput';
4. import { WINE_ANSWERS_URL } from '../../lib/wine-answers';
5. 
6. const CATEGORIES: { key: QuestionCategory; label: string }[] = [
7.   { key: 'color', label: 'Color' },
8.   { key: 'region', label: 'Region' },
9.   { key: 'grape_variety', label: 'Grape Variety' },
10.   { key: 'vintage_year', label: 'Vintage Year' },
11.   { key: 'wine_name', label: 'Wine Name' },
12. ];
13. 
14. // Autocomplete defaults per category — host edits to match their actual wine
15. const DISTRACTOR_DEFAULTS: Record<QuestionCategory, [string, string, string]> = {
16.   color: ['Blanc', 'Rosé', 'Orange'],
17.   region: ['Loire', 'Bourgogne', 'Languedoc'],
18.   grape_variety: ['Pinot Noir', 'Syrah', 'Cabernet Sauvignon'],
19.   vintage_year: ['2015', '2016', '2018'],
20.   wine_name: ['Château Margaux', 'Château Lafite Rothschild', 'Château Latour'],
21. };
22. 
23. const CORRECT_ANSWER_DEFAULTS: Record<QuestionCategory, string> = {
24.   color: 'Rouge',
25.   region: 'Bordeaux',
26.   grape_variety: 'Merlot',
27.   vintage_year: '2019',
28.   wine_name: 'Château Pétrus',
29. };
30. 
31. const CORRECT_ANSWER_PLACEHOLDERS: Record<QuestionCategory, string> = {
32.   color: 'e.g. Rouge',
33.   region: 'e.g. Bordeaux (France)',
34.   grape_variety: 'e.g. Cabernet Sauvignon',
35.   vintage_year: 'e.g. 2019',
36.   wine_name: 'e.g. Château Pétrus',
37. };
38. 
39. const DISTRACTOR_PLACEHOLDERS: Record<QuestionCategory, [string, string, string]> = {
40.   color: ['e.g. Blanc', 'e.g. Rosé', 'e.g. Orange'],
41.   region: ['e.g. Burgundy (France)', 'e.g. Tuscany (Italy)', 'e.g. Rioja (Spain)'],
42.   grape_variety: ['e.g. Pinot Noir', 'e.g. Merlot', 'e.g. Syrah'],
43.   vintage_year: ['e.g. 2018', 'e.g. 2020', 'e.g. 2016'],
44.   wine_name: ['e.g. Château Margaux', 'e.g. Pétrus', 'e.g. Opus One'],
45. };
46. 
47. interface QuestionFormData {
48.   correctAnswer: string;
49.   distractors: [string, string, string];
50. }
51. 
52. type WineQuestions = Record<QuestionCategory, QuestionFormData>;
53. 
54. interface WineFormData {
55.   name: string;
56.   questions: WineQuestions;
57. }
58. 
59. function emptyWine(): WineFormData {
60.   return {
61.     name: '',
62.     questions: Object.fromEntries(
63.       CATEGORIES.map(({ key }) => [
64.         key,
65.         {
66.           correctAnswer: CORRECT_ANSWER_DEFAULTS[key],
67.           distractors: DISTRACTOR_DEFAULTS[key],
68.         },
69.       ]),
70.     ) as WineQuestions,
71.   };
72. }
73. 
74. function wineFromPayload(wine: CreateWinePayload): WineFormData {
75.   const questions = Object.fromEntries(
76.     CATEGORIES.map(({ key }) => {
77.       const q = wine.questions.find((q) => q.category === key);
78.       return [
79.         key,
80.         {
81.           correctAnswer: q?.correctAnswer ?? CORRECT_ANSWER_DEFAULTS[key],
82.           distractors: (q?.distractors ?? DISTRACTOR_DEFAULTS[key]) as [string, string, string],
83.         },
84.       ];
85.     }),
86.   ) as WineQuestions;
87.   return { name: wine.name, questions };
88. }
89. 
90. interface SessionFormProps {
91.   onSubmit: (payload: CreateSessionPayload) => void;
92.   hostId?: string;
93.   /** Pre-filled wines for editing an existing session */
94.   initialWines?: CreateWinePayload[];
95.   /** Pre-filled title for editing an existing session */
96.   initialTitle?: string;
97.   /** When true, renders in edit mode (different heading + submit label) */
98.   isEditing?: boolean;
99. }
100. 
101. export function SessionForm({ onSubmit, hostId, initialWines, initialTitle, isEditing = false }: SessionFormProps) {
102.   const [wines, setWines] = useState<WineFormData[]>(() =>
103.     initialWines?.length ? initialWines.map(wineFromPayload) : [emptyWine()],
104.   );
105.   const [timerSeconds, setTimerSeconds] = useState(60);
106.   const [title, setTitle] = useState(initialTitle ?? '');
107.   const [error, setError] = useState<string | null>(null);
108.   const [answerOptions, setAnswerOptions] = useState<Record<string, string[]>>({});
109. 
110.   useEffect(() => {
111.     fetch(`${WINE_ANSWERS_URL}/answers`)
112.       .then(res => res.json())
113.       .then(data => setAnswerOptions(data))
114.       .catch(() => {
115.         // Fallback to empty — the combobox still allows free text
116.       });
117.   }, []);
118. 
119.   const updateWineName = (wi: number, value: string) => {
120.     setWines((prev) => {
121.       const next = [...prev];
122.       next[wi] = { ...next[wi], name: value };
