120.     setWines((prev) => {
121.       const next = [...prev];
122.       next[wi] = { ...next[wi], name: value };
123.       return next;
124.     });
125.   };
126. 
127.   const updateAnswer = (
128.     wi: number,
129.     cat: QuestionCategory,
130.     field: 'correctAnswer' | number,
131.     value: string,
132.   ) => {
133.     setWines((prev) => {
134.       const next = [...prev];
135.       const wine = { ...next[wi] };
136.       const q = { ...wine.questions[cat] };
137.       if (field === 'correctAnswer') {
138.         q.correctAnswer = value;
139.       } else {
140.         const distractors = [...q.distractors] as [string, string, string];
141.         distractors[field as number] = value;
142.         q.distractors = distractors;
143.       }
144.       wine.questions = { ...wine.questions, [cat]: q };
145.       next[wi] = wine;
146.       return next;
147.     });
148.   };
149. 
150.   const addWine = () => setWines((prev) => [...prev, emptyWine()]);
151.   const removeWine = (wi: number) =>
152.     setWines((prev) => prev.filter((_, i) => i !== wi));
153. 
154.   const handleSubmit = (e: React.FormEvent) => {
155.     e.preventDefault();
156.     setError(null);
157. 
158.     for (const [wi, wine] of wines.entries()) {
159.       if (!wine.name.trim()) {
160.         setError(`Wine ${wi + 1}: name is required.`);
161.         return;
162.       }
163.       for (const cat of CATEGORIES) {
164.         const q = wine.questions[cat.key];
165.         if (!q.correctAnswer.trim()) {
166.           setError(`Wine ${wi + 1} — ${cat.label}: correct answer is required.`);
167.           return;
168.         }
169.         for (const [di, d] of q.distractors.entries()) {
170.           if (!d.trim()) {
171.             setError(`Wine ${wi + 1} — ${cat.label}: distractor ${di + 1} is required.`);
172.             return;
173.           }
174.         }
175.       }
176.     }
177. 
178.     // Collect custom answers to persist
179.     const customAnswers: { category: string; value: string }[] = [];
180.     for (const wine of wines) {
181.       for (const cat of CATEGORIES) {
182.         const existing = answerOptions[cat.key] || [];
183.         const correctAnswer = wine.questions[cat.key].correctAnswer.trim();
184.         if (correctAnswer && !existing.includes(correctAnswer)) {
185.           customAnswers.push({ category: cat.key, value: correctAnswer });
186.         }
187.         for (const d of wine.questions[cat.key].distractors) {
188.           const trimmed = d.trim();
189.           if (trimmed && !existing.includes(trimmed)) {
190.             customAnswers.push({ category: cat.key, value: trimmed });
191.           }
192.         }
193.       }
194.     }
195. 
196.     // Fire-and-forget: persist custom answers to the collection
197.     for (const { category, value } of customAnswers) {
198.       fetch(`${WINE_ANSWERS_URL}/answers/${category}`, {
199.         method: 'POST',
200.         headers: { 'Content-Type': 'application/json' },
201.         body: JSON.stringify({ value }),
202.       }).catch(() => {});  // Best-effort, don't block session creation
203.     }
204. 
205.     const payload: CreateSessionPayload = {
206.       wines: wines.map(
207.         (wine): CreateWinePayload => ({
208.           name: wine.name.trim(),
209.           questions: CATEGORIES.map((cat) => ({
210.             category: cat.key,
211.             correctAnswer: wine.questions[cat.key].correctAnswer.trim(),
212.             distractors: wine.questions[cat.key].distractors.map((d) =>
213.               d.trim(),
214.             ) as [string, string, string],
215.           })),
216.         }),
217.       ),
218.       timerSeconds,
219.       hostId: hostId ?? '',
220.       title: title.trim() || wines[0]?.name.trim(),
221.     };
222. 
223.     onSubmit(payload);
224.   };
225. 
226.   return (
227.     <form onSubmit={handleSubmit} className="space-y-6 w-full max-w-2xl mx-auto">
228.       <div className="text-center">
229.         <h1 className="text-3xl font-bold text-slate-800">
