249.       </div>
250. 
251.       {/* Timer slider */}
252.       <div className="bg-white border border-slate-200 rounded-2xl p-5 space-y-3">
253.         <label htmlFor="timer-slider" className="block text-sm font-semibold text-slate-700">
254.           Timer per question:{' '}
255.           <span className="text-wine-600">{timerSeconds}s</span>
256.         </label>
257.         <input
258.           id="timer-slider"
259.           type="range"
260.           min={15}
261.           max={120}
262.           step={5}
263.           value={timerSeconds}
264.           onChange={(e) => setTimerSeconds(Number(e.target.value))}
265.           aria-valuemin={15}
266.           aria-valuemax={120}
267.           aria-valuenow={timerSeconds}
268.           aria-valuetext={`${timerSeconds} seconds`}
269.           className="w-full accent-wine-600"
270.         />
271.         <div className="flex justify-between text-xs text-slate-400">
272.           <span>15s</span>
273.           <span>120s</span>
274.         </div>
275.       </div>
276. 
277.       {wines.map((wine, wi) => (
278.         <div key={wi} className="bg-white border border-slate-200 rounded-2xl p-5 space-y-4">
279.           <div className="flex items-center justify-between">
280.             <h2 className="font-semibold text-slate-700 text-lg">Wine {wi + 1}</h2>
281.             {wines.length > 1 && (
282.               <button
283.                 type="button"
284.                 onClick={() => removeWine(wi)}
285.                 className="text-sm text-red-400 hover:text-red-600 transition-colors"
286.               >
287.                 Remove
288.               </button>
289.             )}
290.           </div>
291. 
292.           <div>
293.             <label
294.               htmlFor={`wine-name-${wi}`}
295.               className="block text-sm font-medium text-slate-600 mb-1"
296.             >
297.               Wine name
298.             </label>
299.             <input
300.               id={`wine-name-${wi}`}
301.               type="text"
302.               value={wine.name}
303.               onChange={(e) => updateWineName(wi, e.target.value)}
304.               placeholder="e.g. Château Margaux 2015"
305.               className="w-full border border-slate-300 rounded-lg px-3 py-2 text-slate-800 placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-wine-400"
306.             />
307.           </div>
308. 
309.           {CATEGORIES.map((cat) => (
310.             <div key={cat.key} className="space-y-2">
311.               <p className="text-sm font-semibold text-wine-600 uppercase tracking-wide">
312.                 {cat.label}
313.               </p>
314.               <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
315.                 <div className="relative">
316.                   <ComboboxInput
317.                     id={`wine-${wi}-${cat.key}-correct`}
318.                     options={answerOptions[cat.key] || []}
319.                     value={wine.questions[cat.key].correctAnswer}
320.                     onChange={(val) => updateAnswer(wi, cat.key, 'correctAnswer', val)}
321.                     placeholder={CORRECT_ANSWER_PLACEHOLDERS[cat.key]}
322.                     label={`Wine ${wi + 1} ${cat.label} — correct answer`}
323.                     inputClassName="w-full border border-emerald-300 bg-emerald-50 rounded-lg px-3 py-2 text-slate-800 placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-emerald-400"
324.                   />
325.                   <span className="absolute right-2 top-2 text-xs text-emerald-600 font-medium" aria-hidden="true">✓</span>
326.                 </div>
327.                 {wine.questions[cat.key].distractors.map((d, di) => (
328.                   <div key={di}>
329.                     <ComboboxInput
330.                       id={`wine-${wi}-${cat.key}-distractor-${di}`}
331.                       options={answerOptions[cat.key] || []}
332.                       value={d}
333.                       onChange={(val) => updateAnswer(wi, cat.key, di, val)}
334.                       placeholder={DISTRACTOR_PLACEHOLDERS[cat.key][di]}
335.                       label={`Wine ${wi + 1} ${cat.label} — distractor ${di + 1}`}
336.                     />
337.                   </div>
338.                 ))}
339.               </div>
340.             </div>
341.           ))}
342.         </div>
343.       ))}
344. 
345.       {error && (
346.         <p role="alert" className="text-red-500 text-sm text-center">{error}</p>
347.       )}
348. 
349.       <div className="flex flex-col sm:flex-row gap-3">
350.         <button
351.           type="button"
352.           onClick={addWine}
353.           className="flex-1 border border-wine-300 text-wine-600 rounded-xl py-3 font-medium hover:bg-wine-50 transition-colors"
354.         >
355.           + Add Wine
356.         </button>
357.         <button
358.           type="submit"
359.           className="flex-1 bg-wine-600 text-white rounded-xl py-3 font-semibold hover:bg-wine-700 transition-colors"
360.         >
361.           {isEditing ? 'Update Tasting' : 'Create Tasting'}
362.         </button>
363.       </div>
364.     </form>
365.   );
366. }
