88. interface SessionFormProps {
89.   onSubmit: (payload: CreateSessionPayload) => void;
90.   hostId?: string;
91.   /** Pre-filled wines for editing an existing session */
92.   initialWines?: CreateWinePayload[];
93.   /** Pre-filled title for editing an existing session */
94.   initialTitle?: string;
95.   /** When true, renders in edit mode (different heading + submit label) */
96.   isEditing?: boolean;
97. }
98. 
99. export function SessionForm({ onSubmit, hostId, initialWines, initialTitle, isEditing = false }: SessionFormProps) {
100.   const [wines, setWines] = useState<WineFormData[]>(() =>
101.     initialWines?.length ? initialWines.map(wineFromPayload) : [emptyWine()],
102.   );
103.   const [timerSeconds, setTimerSeconds] = useState(60);
104.   const [title, setTitle] = useState(initialTitle ?? '');
105.   const [error, setError] = useState<string | null>(null);
106.   const [answerOptions, setAnswerOptions] = useState<Record<string, string[]>>({});
107. 
108.   useEffect(() => {
109.     fetch(`${WINE_ANSWERS_URL}/answers`)
110.       .then(res => res.json())
111.       .then(data => setAnswerOptions(data))
112.       .catch(() => {
113.         // Fallback to empty — the combobox still allows free text
114.       });
115.   }, []);
116. 
117.   const updateAnswer = (
118.     wi: number,
119.     cat: QuestionCategory,
120.     field: 'correctAnswer' | number,
121.     value: string,
122.   ) => {
123.     setWines((prev) => {
124.       const next = [...prev];
125.       const wine = { ...next[wi] };
126.       const q = { ...wine.questions[cat] };
127.       if (field === 'correctAnswer') {
128.         q.correctAnswer = value;
129.       } else {
130.         const distractors = [...q.distractors] as [string, string, string];
131.         distractors[field as number] = value;
132.         q.distractors = distractors;
133.       }
134.       wine.questions = { ...wine.questions, [cat]: q };
135.       next[wi] = wine;
136.       return next;
137.     });
138.   };
139. 
140.   const addWine = () => setWines((prev) => [...prev, emptyWine()]);
141.   const removeWine = (wi: number) =>
142.     setWines((prev) => prev.filter((_, i) => i !== wi));
143. 
144.   const handleSubmit = (e: React.FormEvent) => {
145.     e.preventDefault();
146.     setError(null);
147. 
148.     for (const [wi, wine] of wines.entries()) {
149.       for (const cat of CATEGORIES) {
150.         const q = wine.questions[cat.key];
151.         if (!q.correctAnswer.trim()) {
152.           setError(`Wine ${wi + 1} — ${cat.label}: correct answer is required.`);
153.           return;
154.         }
155.         for (const [di, d] of q.distractors.entries()) {
156.           if (!d.trim()) {
157.             setError(`Wine ${wi + 1} — ${cat.label}: distractor ${di + 1} is required.`);
158.             return;
159.           }
160.         }
161.       }
162.     }
163. 
164.     // Collect custom answers to persist
165.     const customAnswers: { category: string; value: string }[] = [];
166.     for (const wine of wines) {
167.       for (const cat of CATEGORIES) {
168.         const existing = answerOptions[cat.key] || [];
169.         const correctAnswer = wine.questions[cat.key].correctAnswer.trim();
170.         if (correctAnswer && !existing.includes(correctAnswer)) {
171.           customAnswers.push({ category: cat.key, value: correctAnswer });
172.         }
173.         for (const d of wine.questions[cat.key].distractors) {
174.           const trimmed = d.trim();
175.           if (trimmed && !existing.includes(trimmed)) {
176.             customAnswers.push({ category: cat.key, value: trimmed });
177.           }
178.         }
179.       }
180.     }
181. 
182.     // Fire-and-forget: persist custom answers to the collection
183.     for (const { category, value } of customAnswers) {
184.       fetch(`${WINE_ANSWERS_URL}/answers/${category}`, {
185.         method: 'POST',
186.         headers: { 'Content-Type': 'application/json' },
187.         body: JSON.stringify({ value }),
188.       }).catch(() => {});  // Best-effort, don't block session creation
189.     }
190. 
191.     const payload: CreateSessionPayload = {
192.       wines: wines.map(
193.         (wine, wi): CreateWinePayload => ({
194.           name: wine.questions.wine_name.correctAnswer.trim() || `Wine ${wi + 1}`,
195.           questions: CATEGORIES.map((cat) => ({
196.             category: cat.key,
197.             correctAnswer: wine.questions[cat.key].correctAnswer.trim(),
198.             distractors: wine.questions[cat.key].distractors.map((d) =>
199.               d.trim(),
200.             ) as [string, string, string],
201.           })),
202.         }),
203.       ),
204.       timerSeconds,
205.       hostId: hostId ?? '',
206.       title: title.trim() || wines[0]?.questions.wine_name.correctAnswer.trim(),
207.     };
208. 
209.     onSubmit(payload);
210.   };
211. 
212.   return (
213.     <form onSubmit={handleSubmit} className="space-y-6 w-full max-w-2xl mx-auto">
214.       <div className="text-center">
215.         <h1 className="text-3xl font-bold text-slate-800">
216.           {isEditing ? 'Edit Blind Tasting' : 'New Blind Tasting'}
217.         </h1>
218.         <p className="text-slate-500 mt-1">Add wines and fill in the answers for each question.</p>
219.       </div>
220. 
221.       {/* Optional tasting title */}
222.       <div className="bg-white border border-slate-200 rounded-2xl p-5">
223.         <label htmlFor="tasting-title" className="block text-sm font-semibold text-slate-700 mb-1">
224.           Tasting title <span className="font-normal text-slate-400">(optional)</span>
225.         </label>
226.         <input
227.           id="tasting-title"
228.           type="text"
229.           value={title}
230.           onChange={(e) => setTitle(e.target.value)}
231.           placeholder='e.g. "Friday Night Tasting"'
232.           className="w-full border border-slate-300 rounded-lg px-3 py-2 text-slate-800 placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-wine-400"
233.         />
234.         <p className="text-xs text-slate-400 mt-1">Leave blank to use the first wine's name (from the Wine Name answer) as title.</p>
235.       </div>
236. 
237.       {/* Timer slider */}
238.       <div className="bg-white border border-slate-200 rounded-2xl p-5 space-y-3">
239.         <label htmlFor="timer-slider" className="block text-sm font-semibold text-slate-700">
240.           Timer per question:{' '}
241.           <span className="text-wine-600">{timerSeconds}s</span>
242.         </label>
243.         <input
244.           id="timer-slider"
245.           type="range"
246.           min={15}
247.           max={120}
248.           step={5}
249.           value={timerSeconds}
250.           onChange={(e) => setTimerSeconds(Number(e.target.value))}
251.           aria-valuemin={15}
252.           aria-valuemax={120}
253.           aria-valuenow={timerSeconds}
254.           aria-valuetext={`${timerSeconds} seconds`}
255.           className="w-full accent-wine-600"
256.         />
257.         <div className="flex justify-between text-xs text-slate-400">
258.           <span>15s</span>
259.           <span>120s</span>
260.         </div>
261.       </div>
262. 
263.       {wines.map((wine, wi) => (
264.         <div key={wi} className="bg-white border border-slate-200 rounded-2xl p-5 space-y-4">
265.           <div className="flex items-center justify-between">
266.             <h2 className="font-semibold text-slate-700 text-lg">
267.               Wine {wi + 1}
268.               {wine.questions.wine_name.correctAnswer && (
269.                 <span className="ml-2 font-normal text-slate-500 text-base">
270.                   — {wine.questions.wine_name.correctAnswer}
271.                 </span>
272.               )}
273.             </h2>
274.             {wines.length > 1 && (
275.               <button
276.                 type="button"
277.                 onClick={() => removeWine(wi)}
