279.               >
280.                 Remove
281.               </button>
282.             )}
283.           </div>
284. 
285.           {CATEGORIES.map((cat) => (
286.             <div key={cat.key} className="space-y-2">
287.               <p className="text-sm font-semibold text-wine-600 uppercase tracking-wide">
288.                 {cat.label}
289.               </p>
290.               <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
291.                 <div className="relative">
292.                   <ComboboxInput
293.                     id={`wine-${wi}-${cat.key}-correct`}
294.                     options={answerOptions[cat.key] || []}
295.                     value={wine.questions[cat.key].correctAnswer}
296.                     onChange={(val) => updateAnswer(wi, cat.key, 'correctAnswer', val)}
297.                     placeholder={CORRECT_ANSWER_PLACEHOLDERS[cat.key]}
298.                     label={`Wine ${wi + 1} ${cat.label} — correct answer`}
299.                     inputClassName="w-full border border-emerald-300 bg-emerald-50 rounded-lg px-3 py-2 text-slate-800 placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-emerald-400"
300.                   />
301.                   <span className="absolute right-2 top-2 text-xs text-emerald-600 font-medium" aria-hidden="true">✓</span>
302.                 </div>
303.                 {wine.questions[cat.key].distractors.map((d, di) => (
