           type="submit"
           className="flex-1 bg-wine-600 text-white rounded-xl py-3 font-semibold hover:bg-wine-700 transition-colors"
         >
           {isEditing ? 'Update Tasting' : 'Create Tasting'}
         </button>
       </div>
     </form>
