  ctx.timer.clear();
  ctx.phase = 'ended';
  const rankings = buildRankings(ctx.participants);

  await saveState(ctx);
  await upsertKvSession(ctx, { status: 'ended', finalRankings: rankings });

  ctx.broadcast('game:final_leaderboard', { rankings });
  ctx.broadcast('session:ended', {});
}
